/**
 * Gate Runtime (T-TL-34 Refactored)
 * 
 * Production gate system that controls access to gated content (price, brochure).
 * Now uses DreamRealityRuntime for universal state management instead of
 * hardcoded state logic.
 * 
 * Thin wrapper around DreamRealityRuntime that provides gate-specific API
 * and brochure download interception.
 */

import { DreamRealityRuntime } from './dream-reality-runtime.js';
import { ConditionEvaluator } from '../core/condition-evaluator.js';

interface GateConfig {
  sectionId: string;
  token: string;
  endpoint: string;
  anonKey: string;
}

class GateRuntime {
  private config: GateConfig;
  private runtime: DreamRealityRuntime;
  private conditionEvaluator: ConditionEvaluator;
  private pendingDownload: string | null = null;
  private statePath: string;

  constructor(config: GateConfig) {
    this.config = config;
    this.statePath = `${config.sectionId}.state`;
    
    // Create unified runtime with gate state type
    this.runtime = new DreamRealityRuntime({
      stateTypes: {
        [this.statePath]: {
          type: 'enum',
          values: ['locked', 'modal', 'unlocked'],
          default: 'locked',
          persist: true,
        },
      },
      context: 'gate',
    });

    // Create condition evaluator with runtime
    this.conditionEvaluator = new ConditionEvaluator(this.runtime);

    this.init();
  }

  private init() {
    // Subscribe to state changes to trigger condition evaluation
    this.runtime.onStateChange(() => {
      this.conditionEvaluator.evaluateAll();
    });

    // Apply initial state (evaluates conditions with persisted state)
    this.conditionEvaluator.evaluateAll();

    // Intercept brochure link clicks
    this.setupBrochureInterception();

    // Expose API (backward compatible)
    (window as any).dlrGate = {
      open: (callback?: () => void) => this.open(callback),
      unlock: () => this.unlock(),
      isUnlocked: () => this.isUnlocked(),
    };
  }

  private setupBrochureInterception() {
    document.addEventListener('click', (e) => {
      const target = e.target as HTMLElement;
      const link = target.closest('[data-brochure-link]') as HTMLAnchorElement;
      
      if (link && !this.isUnlocked()) {
        e.preventDefault();
        e.stopPropagation();
        
        // Store the download URL
        this.pendingDownload = link.href;
        
        // Open the gate
        this.open();
      }
    }, true); // Use capture phase to intercept before other handlers
  }

  public open(callback?: () => void) {
    if (this.isUnlocked()) {
      callback?.();
      return;
    }

    // Use unified runtime to set state
    this.runtime.setState(this.statePath, 'modal');
    
    if (callback) {
      callback();
    }
  }

  public unlock() {
    // Use unified runtime to set state (with persistence)
    this.runtime.setState(this.statePath, 'unlocked', true);

    // If there's a pending download, trigger it immediately
    if (this.pendingDownload) {
      // Use window.location.href instead of link.click() for mobile Safari compatibility
      window.location.href = this.pendingDownload;
      this.pendingDownload = null;
    }
  }

  public isUnlocked(): boolean {
    return this.runtime.getState(this.statePath) === 'unlocked';
  }
}

// Initialize when DOM is ready
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', () => {
    if ((window as any).__DLR) {
      new GateRuntime((window as any).__DLR);
    }
  });
} else {
  if ((window as any).__DLR) {
    new GateRuntime((window as any).__DLR);
  }
}
